import React, { useEffect, useState } from "react"
import { colors } from "../utils/theme"
import { css } from "@emotion/core"

const DownloadButton = props => {
  let [isFirefox, setIsFirefox] = useState(null)
  let [isChrome, setIsChrome] = useState(null)
  useEffect(() => {
    isFirefox = typeof InstallTrigger !== "undefined"
    setIsFirefox(isFirefox)

    isChrome =
      !!window.chrome && (!!window.chrome.webstore || !!window.chrome.runtime)
    setIsChrome(isChrome)
  })

  if (isChrome) {
    return (
      <a
        href="https://chrome.google.com/webstore/detail/zenshare/pomckcogeffbfailipjnpmijpjedakmp"
        css={css`
          text-decoration: none;
          background: ${colors.primary.dark};
          font-size: 16px;
          font-weight: 500;
          color: white;
          border-radius: 4px;
          padding: 8px 12px;
          &:hover {
            background-color: ${colors.primary.darker};
          }
        `}
      >
        {props.text ? props.text : "Download for Chrome"}
      </a>
    )
  } else if (isFirefox) {
    return (
      <a
        href="https://addons.mozilla.org/firefox/addon/zenshare"
        css={css`
          text-decoration: none;
          background: ${colors.primary.dark};
          font-size: 16px;
          font-weight: 500;
          color: white;
          border-radius: 4px;
          padding: 8px 12px;
          &:hover {
            background-color: ${colors.primary.darker};
          }
        `}
      >
        {props.text ? props.text : "Download for Firefox"}
      </a>
    )
  } else {
    return (
      <p
        css={css`
          font-style: italic;
          color: grey;
        `}
      >
        Available for Chrome and Firefox for now
      </p>
    )
  }
}

export default DownloadButton
